+    return replaceInstUsesWith(SI, FalseVal);
+  if (match(CondVal, m_Not(m_Value(X))) && match(TrueVal, m_Zero()) && FalseVal == X)
+    return replaceInstUsesWith(SI, FalseVal);
+  // select (xor X, true), Y, false -> false if X and Y are known equal
+  if (match(CondVal, m_Not(m_Value(X))) && match(FalseVal, m_Zero())) {
+    auto isKnownEqual = [&](Value *A, Value *B) {
+      if (A == B) return true;
+      std::optional<Value *> V = simplifyCmpInst(ICmpInst::ICMP_EQ, A, B,
+                                                 SQ.getWithInstruction(&SI));
+      return V && *V == One;
