+    auto isSignBitTest = [&](Value *V, Value *&Base) -> bool {
+      const APInt *ShAmt;
+      if (match(V, m_Trunc(m_Shr(m_Value(Base), m_APInt(ShAmt))))) {
+        unsigned BitWidth = Base->getType()->getScalarSizeInBits();
+        return ShAmt->getZExtValue() == BitWidth - 1 && V->getType()->isIntOrIntVectorTy(1);
+      }
+      CmpPredicate Pred;
